#ifdef PROFILING
class timer {
public:
    timer(const char *name = 0) : start_time_(0.0), total_time_(0.0) {}
    timer(const char *name, std::ostream &write_on_exit) : start_time_(0.0), total_time_(0.0) {}
    ~timer() {}
    void start() { start_time_ = omp_get_wtime(); }
    void stop() { total_time_ += omp_get_wtime() - start_time_; }
    void reset() { start_time_ = 0.0; total_time_ = 0.0; }
    double getTimeInSeconds() { return total_time_; }
private:
