      d2h_time = 0, close_time = 0, total_time = 0;

static inline void tvsub(const struct timeval *t1, const struct timeval *t0, struct timeval *tdiff)
{
    tdiff->tv_sec = t1->tv_sec - t0->tv_sec;
    tdiff->tv_usec = t1->tv_usec - t0->tv_usec;
    if (tdiff->tv_usec < 0) {
        tdiff->tv_sec--;
        tdiff->tv_usec += 1000000;
    }
}
#endif

template<typename datatype>
void compare_results(const datatype *cpu_results, const datatype *gpu_results, const int size)
{
    char passed = true;
    for (int i = 0; i < size; i++) {
        if (cpu_results[i] != gpu_results[i]) {
            passed = false;
        }
    }
    if (passed) {
        std::cout << "--cambine:passed:-)" << std::endl;
    } else {
        std::cout << "--cambine: failed:-(" << std::endl;
    }
}

void _clCmdParams(int argc, char* argv[])
{
    for (int i = 0; i < argc; ++i) {
        if (argv[i] == NULL || argv[i][0] != '-' || argv[i][1] == '\0') continue;
        switch (argv[i][1]) {
        case 'g':
            if (++i < argc) {
                sscanf(argv[i], "%u", &work_group_size);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("argument parsing error");
            }
            break;
        case 'd':
            if (++i < argc) {
                sscanf(argv[i], "%u", &device_id_inuse);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("argument parsing error");
            }
            break;
        case 'p':
            if (++i < argc) {
                sscanf(argv[i], "%u", &platform_id_inuse);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("argument parsing error");
            }
            break;
        case 't':
            if (++i >= argc) {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("argument parsing error");
            }
            break;
        default:
            break;
        }
    }
}

static void BFS_1(const Node* g_graph_nodes,
                  const int* g_graph_edges,
                  char* g_graph_mask,
                  char* g_updating_graph_mask,
                  char* g_graph_visited,
                  int* g_cost,
                  const int no_of_nodes)
{
#pragma omp parallel for schedule(static)
    for (int tid = 0; tid < no_of_nodes; tid++) {
        if (g_graph_mask[tid]) {
            g_graph_mask[tid] = false;
            int start = g_graph_nodes[tid].starting;
            int end = g_graph_nodes[tid].no_of_edges + start;
            int next_cost = g_cost[tid] + 1;
            for (int i = start; i < end; i++) {
                int id = g_graph_edges[i];
                if (!g_graph_visited[id]) {
                    if (__sync_bool_compare_and_swap(&g_updating_graph_mask[id], (char)false, (char)true)) {
                        g_cost[id] = next_cost;
                    }
                }
            }
        }
    }
}

static void BFS_2(char* g_graph_mask,
                  char* g_updating_graph_mask,
                  char* g_graph_visited,
                  char* g_over,
                  const int no_of_nodes)
{
    int over_int = 0;
#pragma omp parallel for reduction(|:over_int) schedule(static)
    for (int tid = 0; tid < no_of_nodes; tid++) {
        if (g_updating_graph_mask[tid]) {
            g_graph_mask[tid] = true;
            g_graph_visited[tid] = true;
            over_int = 1;
            g_updating_graph_mask[tid] = false;
        }
    }
    *g_over = over_int ? true : false;
}

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost_ref)
{
    char stop;
    int k = 0;
    do {
        stop = false;
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid] = false;
                for (int i = h_graph_nodes[tid].starting; i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
                    int id = h_graph_edges[i];
                    if (!h_graph_visited[id]) {
                        h_cost_ref[id] = h_cost_ref[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
        k++;
    } while (stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost)
{
    char h_over;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);

    gettimeofday(&tv_mem_alloc_start, NULL);
