int
main(int argc, char* argv[]){

	printf("WG size of kernel = %d \n", NUMBER_THREADS);

	params_common common;
	memset(&common, 0, sizeof(params_common));
	common.common_mem = sizeof(params_common);

	char* video_file_name = NULL;
	char* input_file_name = NULL;
	common.frames_processed = -1;

	for (int i = 0; i < argc; ++i) {
		switch (argv[i][1]) {
		case 'f':
			if (++i < argc) {
				video_file_name = argv[i];
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		case 'i':
			if (++i < argc) {
				input_file_name = argv[i];
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		case 'h':
			printf("%s <-f video_file> <-i input_file> <-n num_frames> [-p platform_id] [-n device_id]\n", argv[0]);
			return 0;
		case 'n':
			if (++i < argc) {
				common.frames_processed = atoi(argv[i]);
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		case 'p':
			if (++i < argc) {
				platform_id_inuse = atoi(argv[i]);
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		case 'd':
			if (++i < argc) {
				device_id_inuse = atoi(argv[i]);
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		}
	}

	if (input_file_name == NULL || video_file_name == NULL) {
		printf("Input or video file name is missing\n");
		return 0;
	}

	avi_t* frames;

	frames = (avi_t*)AVI_open_input_file(video_file_name, 1);
	if (frames == NULL)  {
		AVI_print_error((char *)"Error with AVI_open_input_file");
		return -1;
	}

	common.no_frames = AVI_video_frames(frames);
	common.frame_rows = AVI_video_height(frames);
	common.frame_cols = AVI_video_width(frames);
	common.frame_elem = common.frame_rows * common.frame_cols;
	common.frame_mem = sizeof(fp) * common.frame_elem;

	if (common.frames_processed < 0 || common.frames_processed > common.no_frames){
		printf("ERROR: %d is an incorrect number of frames specified, select in the range of 0-%d\n", common.frames_processed, common.no_frames);
		return 0;
	}

	read_parameters(input_file_name,
					&common.tSize,
					&common.sSize,
					&common.maxMove,
					&common.alpha);

	read_header(input_file_name,
				&common.endoPoints,
				&common.epiPoints);

	common.allPoints = common.endoPoints + common.epiPoints;

	common.endo_mem = sizeof(int) * common.endoPoints;

	int* endoRow = (int*)checked_calloc(common.endoPoints, sizeof(int));
	int* endoCol = (int*)checked_calloc(common.endoPoints, sizeof(int));
	int* tEndoRowLoc = (int*)checked_calloc((size_t)common.endoPoints * common.no_frames, sizeof(int));
	int* tEndoColLoc = (int*)checked_calloc((size_t)common.endoPoints * common.no_frames, sizeof(int));

	common.epi_mem = sizeof(int) * common.epiPoints;

	int* epiRow = (int*)checked_calloc(common.epiPoints, sizeof(int));
	int* epiCol = (int*)checked_calloc(common.epiPoints, sizeof(int));
	int* tEpiRowLoc = (int*)checked_calloc((size_t)common.epiPoints * common.no_frames, sizeof(int));
	int* tEpiColLoc = (int*)checked_calloc((size_t)common.epiPoints * common.no_frames, sizeof(int));

	read_data(input_file_name,
			  common.endoPoints,
			  endoRow,
			  endoCol,
			  common.epiPoints,
			  epiRow,
			  epiCol);

	kernel_gpu_opencl_wrapper(common,
							  endoRow,
							  endoCol,
							  tEndoRowLoc,
							  tEndoColLoc,
							  epiRow,
							  epiCol,
							  tEpiRowLoc,
							  tEpiColLoc,
							  frames);

#ifdef OUTPUT
	write_data("result.txt",
			   common.no_frames,
			   common.frames_processed,
			   common.endoPoints,
			   tEndoRowLoc,
			   tEndoColLoc,
			   common.epiPoints,
			   tEpiRowLoc,
			   tEpiColLoc);
#endif

	free(endoRow);
	free(endoCol);
	free(tEndoRowLoc);
	free(tEndoColLoc);

	free(epiRow);
	free(epiCol);
	free(tEpiRowLoc);
	free(tEpiColLoc);

	return 0;
}

