static void tvsub_local(const struct timeval *end, const struct timeval *start, struct timeval *res) {
	res->tv_sec = end->tv_sec - start->tv_sec;
	res->tv_usec = end->tv_usec - start->tv_usec;
	if (res->tv_usec < 0) {
		res->tv_sec--;
		res->tv_usec += 1000000;
	}
}

