		common.mask_conv_ioffset = common.mask_conv_ioffset + 1;
	}
	common.mask_conv_joffset = (common.mask_cols - 1) / 2;
	if ((common.mask_cols - 1) % 2 > 0.5) {
		common.mask_conv_joffset = common.mask_conv_joffset + 1;
	}

	fp* d_mask_conv_all = (fp*)malloc((size_t)common.mask_conv_mem * common.allPoints);

	fp* d_in_mod_temp_all = (fp*)malloc(sizeof(fp) * (size_t)common.in_elem * common.allPoints);
	fp* in_partial_sum_all = (fp*)malloc(sizeof(fp) * (size_t)common.in_cols * common.allPoints);
	fp* in_sqr_partial_sum_all = (fp*)malloc(sizeof(fp) * (size_t)common.in_sqr_rows * common.allPoints);
