#ifdef TEST_CHECKSUM
		for (i = 0; i < CHECK; i++) {
			checksum[i] = 0;
		}
#endif

#pragma omp parallel for schedule(static)
		for (int bx = 0; bx < common.allPoints; bx++) {
			kernel_gpu_openmp_point(
				common,
				frame,
				frame_no,
				d_endoRow,
