				d_in2_sub2_all,
				d_in2_sqr_all,
				d_in2_sqr_sub2_all,
				d_in_sqr_all,
				d_tMask_all,
				d_mask_conv_all,
				d_in_mod_temp_all,
				in_partial_sum_all,
				in_sqr_partial_sum_all,
				par_max_val_all,
				par_max_coo_all,
				in_final_sum_all,
				in_sqr_final_sum_all,
				denomT_all,
				checksum,
				bx);
		}

#ifdef TIMING
		gettimeofday(&tv_kernel_end, NULL);
		tvsub_local(&tv_kernel_end, &tv_kernel_start, &tv);
		kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

		free(frame);

		printf("%d ", frame_no);
		fflush(NULL);

#ifdef TEST_CHECKSUM
		printf("CHECKSUM:\n");
		for (i = 0; i < CHECK; i++) {
			printf("%f ", checksum[i]);
		}
		printf("\n\n");
#endif
	}

	printf("\n");
	fflush(NULL);

#ifdef TIMING
	gettimeofday(&tv_d2h_start, NULL);
#endif
#ifdef TIMING
	gettimeofday(&tv_d2h_end, NULL);
	tvsub_local(&tv_d2h_end, &tv_d2h_start, &tv);
	d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
