        memcpy(dev_c, tempOut, sizeof(float) * count);
        gettimeofday(&t1, NULL);
        tvsub(&t1, &t0, &tv);
        h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    }
#else
    memcpy(dev_a, tIn, sizeof(float) * count);
    memcpy(dev_b, pIn, sizeof(float) * count);
    memcpy(dev_c, tempOut, sizeof(float) * count);
#endif

    {
        float *d_a = dev_a;
        float *d_b = dev_b;
        float *d_c = dev_c;

        int j;
        for (j = 0; j < iterations; j++) {
#ifdef TIMING
            struct timeval t0, t1;
            gettimeofday(&t0, NULL);
#endif
            hotspotOpt1(d_b, d_a, d_c, stepDivCap,
                        numCols, numRows, layers,
                        ce, cw, cn, cs, ct, cb, cc);
#ifdef TIMING
            gettimeofday(&t1, NULL);
