static void lud_internal_block(float *m, int matrix_dim, int offset, int bx, int by)
{
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];
    int tx, ty, i;
    int global_row_id;
    int global_col_id;
    float sum;

    global_row_id = offset + (by + 1) * BLOCK_SIZE;
    global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            peri_row[ty * BLOCK_SIZE + tx] =
                m[(offset + ty) * matrix_dim + global_col_id + tx];
            peri_col[ty * BLOCK_SIZE + tx] =
                m[(global_row_id + ty) * matrix_dim + offset + tx];
        }
    }

    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            sum = 0.0f;
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum += peri_col[ty * BLOCK_SIZE + i] *
                       peri_row[i * BLOCK_SIZE + tx];
            }
            m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int i;

    omp_set_num_threads(omp_num_threads);

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        int blocks;

        lud_diagonal_block(m, matrix_dim, i);

        blocks = (matrix_dim - i) / BLOCK_SIZE - 1;

        if (blocks > 0) {
            int bx, by;

#pragma omp parallel for private(bx) schedule(static)
            for (bx = 0; bx < blocks; bx++) {
                lud_perimeter_block(m, matrix_dim, i, bx);
            }

#pragma omp parallel for private(by, bx) collapse(2) schedule(static)
            for (by = 0; by < blocks; by++) {
                for (bx = 0; bx < blocks; bx++) {
                    lud_internal_block(m, matrix_dim, i, bx, by);
                }
            }
        }
    }

    lud_diagonal_block(m, matrix_dim, i);
}

