}

static void lud_internal_omp(float *m, int matrix_dim, int offset)
{
    int bx, by;
    int blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

    if (blocks <= 0)
        return;

#pragma omp parallel for collapse(2) private(by, bx) schedule(static)
    for (by = 0; by < blocks; by++) {
        for (bx = 0; bx < blocks; bx++) {
            int ty, tx, i;
            int global_row_id = offset + (by + 1) * BLOCK_SIZE;
            int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    float sum = 0.0f;
                    for (i = 0; i < BLOCK_SIZE; i++)
                        sum += m[(global_row_id + ty) * matrix_dim + offset + i] *
                               m[(offset + i) * matrix_dim + global_col_id + tx];
                    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int offset = 0;

    if (omp_num_threads > 0)
        omp_set_num_threads(omp_num_threads);

    if (matrix_dim <= 0)
        return;

    if (matrix_dim < BLOCK_SIZE || (matrix_dim % BLOCK_SIZE) != 0) {
        lud_base_fallback(m, matrix_dim);
        return;
    }

    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {
        lud_diagonal_omp(m, matrix_dim, offset);
        lud_perimeter_omp(m, matrix_dim, offset);
        lud_internal_omp(m, matrix_dim, offset);
    }

    lud_diagonal_omp(m, matrix_dim, offset);
}

#include <omp.h>
#include "common.h"

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

void lud_omp(float *m, int matrix_dim)
{
    int offset, bs;

    if (m == 0 || matrix_dim <= 0)
        return;

    omp_set_num_threads(omp_num_threads);
    bs = BLOCK_SIZE;

    for (offset = 0; offset < matrix_dim; offset += bs) {
        int b = MIN(bs, matrix_dim - offset);
        int r, c, i, j, k;

        /* diagonal block */
        for (i = 0; i < b; i++) {
#pragma omp parallel for private(k) schedule(static)
            for (j = i; j < b; j++) {
                float sum = m[(offset + i) * matrix_dim + (offset + j)];
                for (k = 0; k < i; k++)
                    sum -= m[(offset + i) * matrix_dim + (offset + k)] *
                           m[(offset + k) * matrix_dim + (offset + j)];
                m[(offset + i) * matrix_dim + (offset + j)] = sum;
            }

#pragma omp parallel for private(k) schedule(static)
            for (j = i + 1; j < b; j++) {
                float sum = m[(offset + j) * matrix_dim + (offset + i)];
                for (k = 0; k < i; k++)
                    sum -= m[(offset + j) * matrix_dim + (offset + k)] *
                           m[(offset + k) * matrix_dim + (offset + i)];
                m[(offset + j) * matrix_dim + (offset + i)] =
                    sum / m[(offset + i) * matrix_dim + (offset + i)];
            }
        }

        if (offset + b >= matrix_dim)
            continue;

        /* perimeter row blocks */
#pragma omp parallel for private(c, i, j, k) schedule(static)
        for (c = offset + b; c < matrix_dim; c += bs) {
            int w = MIN(bs, matrix_dim - c);
            for (i = 1; i < b; i++) {
                for (j = 0; j < w; j++) {
                    float sum = m[(offset + i) * matrix_dim + (c + j)];
                    for (k = 0; k < i; k++)
                        sum -= m[(offset + i) * matrix_dim + (offset + k)] *
                               m[(offset + k) * matrix_dim + (c + j)];
                    m[(offset + i) * matrix_dim + (c + j)] = sum;
                }
            }
        }

        /* perimeter column blocks */
#pragma omp parallel for private(r, i, j, k) schedule(static)
        for (r = offset + b; r < matrix_dim; r += bs) {
            int h = MIN(bs, matrix_dim - r);
            for (i = 0; i < h; i++) {
                for (j = 0; j < b; j++) {
                    float sum = m[(r + i) * matrix_dim + (offset + j)];
                    for (k = 0; k < j; k++)
                        sum -= m[(r + i) * matrix_dim + (offset + k)] *
                               m[(offset + k) * matrix_dim + (offset + j)];
                    m[(r + i) * matrix_dim + (offset + j)] =
                        sum / m[(offset + j) * matrix_dim + (offset + j)];
                }
            }
        }

        /* internal blocks */
#pragma omp parallel for collapse(2) private(r, c, i, j, k) schedule(static)
        for (r = offset + b; r < matrix_dim; r += bs) {
            for (c = offset + b; c < matrix_dim; c += bs) {
                int h = MIN(bs, matrix_dim - r);
                int w = MIN(bs, matrix_dim - c);
                for (i = 0; i < h; i++) {
                    for (j = 0; j < w; j++) {
                        float sum = 0.0f;
                        for (k = 0; k < b; k++)
                            sum += m[(r + i) * matrix_dim + (offset + k)] *
                                   m[(offset + k) * matrix_dim + (c + j)];
                        m[(r + i) * matrix_dim + (c + j)] -= sum;
                    }
                }
            }
        }
    }
}

