    for(i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * ( b11_1*finavalu_temp[0][i] + b11_4*finavalu_temp[3][i] + b11_5*finavalu_temp[4][i] + b11_6*finavalu_temp[5][i] + b11_7*finavalu_temp[6][i] + b11_8*finavalu_temp[7][i] + b11_9*finavalu_temp[8][i] + b11_10*finavalu_temp[9][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[10], com,
           timecopyin, timecopykernel, timecopyout);

    timeinst_temp = timeinst;
    for(i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * ( b12_1*finavalu_temp[0][i] + b12_6*finavalu_temp[5][i] + b12_7*finavalu_temp[6][i] + b12_8*finavalu_temp[7][i] + b12_9*finavalu_temp[8][i] + b12_10*finavalu_temp[9][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[11], com,
           timecopyin, timecopykernel, timecopyout);

    timeinst_temp = timeinst+h;
    for(i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * ( b13_1*finavalu_temp[0][i] + b13_4*finavalu_temp[3][i] + b13_5*finavalu_temp[4][i] + b13_6*finavalu_temp[5][i] + b13_7*finavalu_temp[6][i] + b13_8*finavalu_temp[7][i] + b13_9*finavalu_temp[8][i] + b13_10*finavalu_temp[9][i] + finavalu_temp[11][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[12], com,
           timecopyin, timecopykernel, timecopyout);

    for(i=0; i<EQUATIONS; i++){
        finavalu[i] = initvalu[i] + h * (c_1_11 * (finavalu_temp[0][i] + finavalu_temp[10][i]) +
                                         c6 * finavalu_temp[5][i] +
                                         c_7_8 * (finavalu_temp[6][i] + finavalu_temp[7][i]) +
                                         c_9_10 * (finavalu_temp[8][i] + finavalu_temp[9][i]));
    }

    for(i=0; i<EQUATIONS; i++){
        error[i] = fabs(err_factor * (finavalu_temp[0][i] + finavalu_temp[10][i] - finavalu_temp[11][i] - finavalu_temp[12][i]));
    }

    for (i = 0; i < 13; i++) {
        free(finavalu_temp[i]);
    }
    free(finavalu_temp);
    free(initvalu_temp);
}

static int solver(fp **y,
                  fp *x,
                  int xmax,
                  fp *params,
                  fp *com,
                  long long *timecopyin,
                  long long *timecopykernel,
                  long long *timecopyout) {

    fp err_exponent;
    int error;
    int outside;
    fp h;
    fp h_init;
    fp tolerance;
    int xmin;

    fp scale_min;
    fp scale_fina;
    fp *err = (fp *)malloc(EQUATIONS * sizeof(fp));
    fp *scale = (fp *)malloc(EQUATIONS * sizeof(fp));
    fp *yy = (fp *)malloc(EQUATIONS * sizeof(fp));

    int i, j, k;

    err_exponent = 1.0f / 7.0f;
    h_init = 1.0f;
    h = h_init;
    xmin = 0;
    tolerance = 10.0f / (fp)(xmax-xmin);

    x[0] = 0;

    if (xmax < xmin || h <= 0.0f){
        free(err);
        free(scale);
        free(yy);
        return -2;
    }

    if (xmax == xmin){
        free(err);
        free(scale);
        free(yy);
        return 0;
    }

    if (h > (xmax - xmin)) {
        h = (fp)xmax - (fp)xmin;
    }

    printf("Time Steps: ");
    fflush(0);

    for(k=1; k<=xmax; k++) {

        x[k] = k-1;
        h = h_init;
        scale_fina = 1.0f;

        for (j = 0; j < ATTEMPTS; j++) {

            error = 0;
            outside = 0;
            scale_min = MAX_SCALE_FACTOR;

            embedded_fehlberg_7_8(x[k],
                                  h,
                                  y[k-1],
                                  y[k],
                                  err,
                                  params,
                                  com,
                                  timecopyin,
                                  timecopykernel,
                                  timecopyout);

            for(i=0; i<EQUATIONS; i++){
                if(err[i] > 0){
                    error = 1;
                }
            }
            if (error != 1) {
                scale_fina = MAX_SCALE_FACTOR;
                break;
            }

            for(i=0; i<EQUATIONS; i++){
                if(y[k-1][i] == 0.0f){
                    yy[i] = tolerance;
                }
                else{
                    yy[i] = fabs(y[k-1][i]);
                }
                scale[i] = 0.8f * pow(tolerance * yy[i] / err[i], err_exponent);
                if(scale[i] < scale_min){
                    scale_min = scale[i];
                }
            }
            scale_fina = min(max(scale_min, MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

            for(i=0; i<EQUATIONS; i++){
                if ( err[i] > ( tolerance * yy[i] ) ){
                    outside = 1;
                }
            }
            if (outside == 0){
                break;
            }

            h = h * scale_fina;

            if (h >= 0.9f) {
                h = 0.9f;
            }

            if ( x[k] + h > (fp)xmax ){
                h = (fp)xmax - x[k];
            }
            else if ( x[k] + h + 0.5f * h > (fp)xmax ){
                h = 0.5f * h;
            }
        }

        x[k] = x[k] + h;

        if ( j >= ATTEMPTS ) {
            free(err);
            free(scale);
            free(yy);
            return -1;
        }

        printf("%d ", k);
        fflush(0);
    }

    printf("\n");
    fflush(0);

    free(err);
    free(scale);
    free(yy);

    return 0;
}

int kernel_gpu_opencl_wrapper(int xmax,
                              int workload,
                              fp ***y,
                              fp **x,
                              fp **params,
                              fp *com) {

    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long timecopyin = 0;
    long long timekernel = 0;
    long long timecopyout = 0;
    long long timeother;
    int i;
    int status;

    time0 = get_time_local();

    printf("Platform: OpenMP\n");
    printf("Device: CPU\n");
    printf("-----OpenCL Compiler Output-----\n");
    printf("--------------------------------\n");

    time1 = get_time_local();

    time2 = get_time_local();

    for(i=0; i<workload; i++){
        status = solver(y[i],
                        x[i],
                        xmax,
                        params[i],
                        com,
                        &timecopyin,
                        &timekernel,
                        &timecopyout);

        if(status != 0){
            printf("STATUS: %d\n", status);
        }
    }

    time3 = get_time_local();

    time4 = get_time_local();

    printf("Time spent in different stages of the application:\n");
    printf("%15.12f s, %15.12f %% : CPU: GPU SETUP\n",
           (float) (time1-time0) / 1000000.0f,
           (float) (time1-time0) / (float) (time4-time0) * 100.0f);
    printf("%15.12f s, %15.12f %% : CPU: ALLOCATE GPU MEMORY\n",
           (float) (time2-time1) / 1000000.0f,
           (float) (time2-time1) / (float) (time4-time0) * 100.0f);
    printf("%15.12f s, %15.12f %% : GPU: COMPUTATION\n",
           (float) (time3-time2) / 1000000.0f,
           (float) (time3-time2) / (float) (time4-time0) * 100.0f);

    printf("\tGPU: COMPUTATION Components:\n");
    printf("\t%15.12f s, %15.12f %% : GPU: COPY DATA IN\n",
           (float) (timecopyin) / 1000000.0f,
           (float) (timecopyin) / (float) (time4-time0) * 100.0f);
    printf("\t%15.12f s, %15.12f %% : GPU: KERNEL\n",
           (float) (timekernel) / 1000000.0f,
           (float) (timekernel) / (float) (time4-time0) * 100.0f);
    printf("\t%15.12f s, %15.12f %% : GPU: COPY DATA OUT\n",
           (float) (timecopyout) / 1000000.0f,
           (float) (timecopyout) / (float) (time4-time0) * 100.0f);

    timeother = time3-time2-timecopyin-timekernel-timecopyout;
    printf("\t%15.12f s, %15.12f %% : GPU: OTHER\n",
           (float) (timeother) / 1000000.0f,
           (float) (timeother) / (float) (time4-time0) * 100.0f);

    printf("%15.12f s, %15.12f %% : CPU: FREE GPU MEMORY\n",
           (float) (time4-time3) / 1000000.0f,
           (float) (time4-time3) / (float) (time4-time0) * 100.0f);
    printf("Total time:\n");
    printf("%.12f s\n",
           (float) (time4-time0) / 1000000.0f);

    return 0;
}

