#include <omp.h>

#ifndef fp
#define fp float
#endif

#ifndef EQUATIONS
#define EQUATIONS 91
#endif

#ifndef PARAMETERS
#define PARAMETERS 16
#endif

#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125f
#define MAX_SCALE_FACTOR 4.0f
#define max(x,y) ( (x) < (y) ? (y) : (x) )
#define min(x,y) ( (x) < (y) ? (x) : (y) )

extern int device_id_inuse;
extern int platform_id_inuse;

void ecc(fp timeinst,
         fp *initvalu,
         int initvalu_offset,
         fp *parameter,
         int parameter_offset,
