static int
solver(fp **y,
       fp *x,
       int xmax,
       fp *params,
       fp *com,
       long long *timecopyin,
       long long *timecopykernel,
       long long *timecopyout) {

    fp err_exponent;
    int error;
    int outside;
    fp h;
    fp h_init;
    fp tolerance;
    int xmin;

    fp scale_min;
    fp scale_fina;
    fp *err = (fp *) malloc(EQUATIONS * sizeof(fp));
    fp *scale = (fp *) malloc(EQUATIONS * sizeof(fp));
    fp *yy = (fp *) malloc(EQUATIONS * sizeof(fp));

    int i, j, k;

    err_exponent = 1.0f / 7.0f;
    h_init = 1.0f;
    h = h_init;
    xmin = 0;
    tolerance = 10.0f / (fp)(xmax-xmin);

    x[0] = 0;

    if (xmax < xmin || h <= 0.0f){
        free(err);
        free(scale);
        free(yy);
        return -2;
    }

    if (xmax == xmin){
        free(err);
        free(scale);
        free(yy);
        return 0;
    }

    if (h > (xmax - xmin)) {
        h = (fp)xmax - (fp)xmin;
    }

    printf("Time Steps: ");
    fflush(0);

    for(k=1; k<=xmax; k++) {

        x[k] = (fp)(k-1);
        h = h_init;
        scale_fina = 1.0f;

        for (j = 0; j < ATTEMPTS; j++) {

            error = 0;
            outside = 0;
            scale_min = MAX_SCALE_FACTOR;

            embedded_fehlberg_7_8(x[k],
                                  h,
                                  y[k-1],
                                  y[k],
                                  err,
                                  params,
                                  com,
                                  timecopyin,
                                  timecopykernel,
                                  timecopyout);

            for(i=0; i<EQUATIONS; i++){
                if(err[i] > 0){
                    error = 1;
                }
            }
            if (error != 1) {
                scale_fina = MAX_SCALE_FACTOR;
                break;
            }

            for(i=0; i<EQUATIONS; i++){
                if(y[k-1][i] == 0.0f){
                    yy[i] = tolerance;
                }
                else{
                    yy[i] = fabsf(y[k-1][i]);
                }
                scale[i] = 0.8f * powf(tolerance * yy[i] / err[i], err_exponent);
                if(scale[i] < scale_min){
                    scale_min = scale[i];
                }
            }
            scale_fina = min(max(scale_min, MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

            for(i=0; i<EQUATIONS; i++){
                if (err[i] > (tolerance * yy[i])){
                    outside = 1;
                }
            }
            if (outside == 0){
                break;
            }

            h = h * scale_fina;

            if (h >= 0.9f) {
                h = 0.9f;
            }

            if (x[k] + h > (fp)xmax){
                h = (fp)xmax - x[k];
            }
            else if (x[k] + h + 0.5f * h > (fp)xmax){
                h = 0.5f * h;
            }
        }

        x[k] = x[k] + h;

        if (j >= ATTEMPTS) {
            free(err);
            free(scale);
            free(yy);
            return -1;
        }

        printf("%d ", k);
        fflush(0);
    }

    printf("\n");
    fflush(0);

    free(err);
    free(scale);
    free(yy);

    return 0;
}

int
kernel_gpu_opencl_wrapper(int xmax,
                          int workload,
                          fp ***y,
                          fp **x,
                          fp **params,
                          fp *com) {

    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long timecopyin = 0;
    long long timekernel = 0;
    long long timecopyout = 0;
