        if(status != 0){
            printf("STATUS: %d\n", status);
        }
    }

    time3 = get_time_local();

    time4 = get_time_local();

    printf("Time spent in different stages of the application:\n");
    printf("%15.12f s, %15.12f % : CPU: GPU SETUP\n", (float) (time1-time0) / 1000000.0f, (float) (time1-time0) / (float) (time4-time0) * 100.0f);
    printf("%15.12f s, %15.12f % : CPU: ALLOCATE GPU MEMORY\n", (float) (time2-time1) / 1000000.0f, (float) (time2-time1) / (float) (time4-time0) * 100.0f);
    printf("%15.12f s, %15.12f % : GPU: COMPUTATION\n", (float) (time3-time2) / 1000000.0f, (float) (time3-time2) / (float) (time4-time0) * 100.0f);

    printf("\tGPU: COMPUTATION Components:\n");
    printf("\t%15.12f s, %15.12f % : GPU: COPY DATA IN\n", (float) (timecopyin) / 1000000.0f, (float) (timecopyin) / (float) (time4-time0) * 100.0f);
    printf("\t%15.12f s, %15.12f % : GPU: KERNEL\n", (float) (timekernel) / 1000000.0f, (float) (timekernel) / (float) (time4-time0) * 100.0f);
    printf("\t%15.12f s, %15.12f % : GPU: COPY DATA OUT\n", (float) (timecopyout) / 1000000.0f, (float) (timecopyout) / (float) (time4-time0) * 100.0f);
    timeother = time3-time2-timecopyin-timekernel-timecopyout;
    printf("\t%15.12f s, %15.12f % : GPU: OTHER\n", (float) (timeother) / 1000000.0f, (float) (timeother) / (float) (time4-time0) * 100.0f);

    printf("%15.12f s, %15.12f % : CPU: FREE GPU MEMORY\n", (float) (time4-time3) / 1000000.0f, (float) (time4-time3) / (float) (time4-time0) * 100.0f);
    printf("Total time:\n");
    printf("%.12f s\n", (float) (time4-time0) / 1000000.0f);

    return 0;
}

