int
kernel_gpu_opencl_wrapper(int xmax,
                          int workload,
                          fp ***y,
                          fp **x,
                          fp **params,
                          fp *com)
{
    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long timecopyin = 0;
    long long timekernel = 0;
    long long timecopyout = 0;
    long long timeother;

    time0 = get_time();

    printf("Platform: OpenMP\n");
    printf("Device: CPU\n");
    printf("-----OpenCL Compiler Output-----\n");
    printf("--------------------------------\n");

