#define SCORE(arr, i, j) arr[(j) + (i) * (BLOCK_SIZE + 1)]
#define REF(arr, i, j)   arr[(j) + (i) * BLOCK_SIZE]

static inline void compute_block(const int *reference_d,
                                 int *input_itemsets_d,
                                 int cols,
                                 int penalty,
                                 int b_index_x,
                                 int b_index_y,
                                 int offset_r,
                                 int offset_c) {
    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    int base = offset_r * cols + offset_c;
    int block_base = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    SCORE(input_itemsets_l, 0, 0) = input_itemsets_d[block_base];

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            REF(reference_l, ty, tx) = reference_d[block_base + (cols + 1) + tx + cols * ty];
        }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(input_itemsets_l, tx + 1, 0) = input_itemsets_d[block_base + cols * (tx + 1)];
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(input_itemsets_l, 0, tx + 1) = input_itemsets_d[block_base + tx + 1];
    }

    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;

            SCORE(input_itemsets_l, t_index_y, t_index_x) =
                maximum(SCORE(input_itemsets_l, t_index_y - 1, t_index_x - 1) +
                            REF(reference_l, t_index_y - 1, t_index_x - 1),
                        SCORE(input_itemsets_l, t_index_y, t_index_x - 1) - penalty,
                        SCORE(input_itemsets_l, t_index_y - 1, t_index_x) - penalty);
        }
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;

            SCORE(input_itemsets_l, t_index_y, t_index_x) =
                maximum(SCORE(input_itemsets_l, t_index_y - 1, t_index_x - 1) +
                            REF(reference_l, t_index_y - 1, t_index_x - 1),
                        SCORE(input_itemsets_l, t_index_y, t_index_x - 1) - penalty,
                        SCORE(input_itemsets_l, t_index_y - 1, t_index_x) - penalty);
        }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            input_itemsets_d[block_base + (cols + 1) + tx + cols * ty] =
                SCORE(input_itemsets_l, ty + 1, tx + 1);
        }
    }
}

static void nw_kernel1_omp(const int *reference_d,
                           int *input_itemsets_d,
                           int *output_itemsets_d,
                           int cols,
                           int penalty,
                           int blk,
                           int block_width,
                           int worksize,
                           int offset_r,
                           int offset_c) {
#pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blk; bx++) {
        int b_index_x = bx;
        int b_index_y = blk - 1 - bx;
        compute_block(reference_d, input_itemsets_d, cols, penalty,
                      b_index_x, b_index_y, offset_r, offset_c);
    }
    (void)output_itemsets_d;
    (void)block_width;
    (void)worksize;
}

static void nw_kernel2_omp(const int *reference_d,
                           int *input_itemsets_d,
                           int *output_itemsets_d,
                           int cols,
                           int penalty,
                           int blk,
                           int block_width,
                           int worksize,
                           int offset_r,
                           int offset_c) {
#pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blk; bx++) {
        int b_index_x = bx + block_width - blk;
        int b_index_y = block_width - bx - 1;
        compute_block(reference_d, input_itemsets_d, cols, penalty,
                      b_index_x, b_index_y, offset_r, offset_c);
    }
    (void)output_itemsets_d;
    (void)worksize;
}

