    return t.tv_sec + t.tv_usec * 1e-6;
}

static inline void process_block(const int *reference, int *input_itemsets, int cols, int penalty,
                                 int b_index_y, int b_index_x, int base)
{
    int start = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    for (int i = 1; i <= BLOCK_SIZE; i++) {
        int row_base = start + i * cols;
        for (int j = 1; j <= BLOCK_SIZE; j++) {
            int idx = row_base + j;
            input_itemsets[idx] = maximum(input_itemsets[idx - cols - 1] + reference[idx],
                                          input_itemsets[idx - 1] - penalty,
                                          input_itemsets[idx - cols] - penalty);
        }
    }
}

int main(int argc, char **argv)
{
    printf("WG size of kernel = %d \n", BLOCK_SIZE);

    int max_rows, max_cols, penalty;
    char *tempchar;

    if (argc >= 4) {
        max_rows = atoi(argv[1]);
        max_cols = atoi(argv[1]);
        penalty = atoi(argv[2]);
        tempchar = argv[3];

        int cur_arg;
        for (cur_arg = 1; cur_arg < argc; cur_arg++) {
            if (strcmp(argv[cur_arg], "-p") == 0) {
                if (argc >= cur_arg + 1) {
                    platform_id_inuse = atoi(argv[cur_arg + 1]);
                    cur_arg++;
                }
            } else if (strcmp(argv[cur_arg], "-d") == 0) {
                if (argc >= cur_arg + 1) {
                    device_id_inuse = atoi(argv[cur_arg + 1]);
                    cur_arg++;
                }
            }
        }
    } else {
        usage(argc, argv);
        return 1;
    }

    if (atoi(argv[1]) % 16 != 0) {
        fprintf(stderr, "The dimension values must be a multiple of 16\n");
        exit(1);
    }

    max_rows = max_rows + 1;
    max_cols = max_cols + 1;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    int *reference;
    int *input_itemsets;
    int *output_itemsets;

    reference = (int *)malloc(max_rows * max_cols * sizeof(int));
    input_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));
    output_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));

    srand(7);

    for (int i = 0; i < max_cols; i++) {
        for (int j = 0; j < max_rows; j++) {
            input_itemsets[i * max_cols + j] = 0;
        }
    }

    for (int i = 1; i < max_rows; i++) {
        input_itemsets[i * max_cols] = rand() % 10 + 1;
    }

    for (int j = 1; j < max_cols; j++) {
        input_itemsets[j] = rand() % 10 + 1;
    }

    for (int i = 1; i < max_cols; i++) {
        for (int j = 1; j < max_rows; j++) {
            reference[i * max_cols + j] = blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
        }
    }

    for (int i = 1; i < max_rows; i++)
        input_itemsets[i * max_cols] = -i * penalty;
    for (int j = 1; j < max_cols; j++)
        input_itemsets[j] = -j * penalty;

    FILE *fp = fopen(tempchar, "rb");
    if (!fp) {
        printf("ERROR: unable to open '%s'\n", tempchar);
        return -1;
    }
    fclose(fp);

    int worksize = max_cols - 1;
    printf("worksize = %d\n", worksize);

    int offset_r = 0, offset_c = 0;
    int block_width = worksize / BLOCK_SIZE;
    int base = offset_r * max_cols + offset_c;

    if (initialize())
        return -1;

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    gettimeofday(&tv_kernel_start, NULL);
#endif

    printf("Processing upper-left matrix\n");
    for (int blk = 1; blk <= worksize / BLOCK_SIZE; blk++) {
#pragma omp parallel for schedule(static)
        for (int bx = 0; bx < blk; bx++) {
            int b_index_x = bx;
            int b_index_y = blk - 1 - bx;
            process_block(reference, input_itemsets, max_cols, penalty, b_index_y, b_index_x, base);
        }
    }

    printf("Processing lower-right matrix\n");
    for (int blk = worksize / BLOCK_SIZE - 1; blk >= 1; blk--) {
#pragma omp parallel for schedule(static)
        for (int bx = 0; bx < blk; bx++) {
            int b_index_x = bx + block_width - blk;
            int b_index_y = block_width - bx - 1;
            process_block(reference, input_itemsets, max_cols, penalty, b_index_y, b_index_x, base);
        }
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    memcpy(output_itemsets, input_itemsets, max_cols * max_rows * sizeof(int));

#ifdef TRACEBACK
    FILE *fpo = fopen("result.txt", "w");
    fprintf(fpo, "print traceback value GPU:\n");

    for (int i = max_rows - 2, j = max_rows - 2; i >= 0, j >= 0;) {
        int nw, n, w, traceback;
        if (i == max_rows - 2 && j == max_rows - 2)
            fprintf(fpo, "%d ", output_itemsets[i * max_cols + j]);
        if (i == 0 && j == 0)
            break;
        if (i > 0 && j > 0) {
            nw = output_itemsets[(i - 1) * max_cols + j - 1];
            w = output_itemsets[i * max_cols + j - 1];
            n = output_itemsets[(i - 1) * max_cols + j];
        } else if (i == 0) {
            nw = n = LIMIT;
            w = output_itemsets[i * max_cols + j - 1];
        } else if (j == 0) {
            nw = w = LIMIT;
            n = output_itemsets[(i - 1) * max_cols + j];
        } else {
        }

        int new_nw, new_w, new_n;
        new_nw = nw + reference[i * max_cols + j];
        new_w = w - penalty;
        new_n = n - penalty;

        traceback = maximum(new_nw, new_w, new_n);
        if (traceback == new_nw)
            traceback = nw;
        if (traceback == new_w)
            traceback = w;
        if (traceback == new_n)
            traceback = n;

        fprintf(fpo, "%d ", traceback);

        if (traceback == nw) {
            i--;
            j--;
            continue;
        } else if (traceback == w) {
            j--;
            continue;
        } else if (traceback == n) {
            i--;
            continue;
        } else
            ;
    }

    fclose(fpo);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    printf("Computation Done\n");

    if (shutdown())
        return -1;

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    free(reference);
    free(input_itemsets);
    free(output_itemsets);

    return 0;
}

