static inline void process_tile(const int *reference_d,
                                int *input_itemsets_d,
                                int cols,
                                int penalty,
                                int b_index_y,
                                int b_index_x,
                                int offset_r,
                                int offset_c)
{
    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

#define SCORE(i, j) input_itemsets_l[(j) + (i) * (BLOCK_SIZE + 1)]
#define REF(i, j)   reference_l[(j) + (i) * BLOCK_SIZE]

    int start_row = offset_r + BLOCK_SIZE * b_index_y;
    int start_col = offset_c + BLOCK_SIZE * b_index_x;

    SCORE(0, 0) = input_itemsets_d[start_row * cols + start_col];

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(tx + 1, 0) = input_itemsets_d[(start_row + tx + 1) * cols + start_col];
        SCORE(0, tx + 1) = input_itemsets_d[start_row * cols + start_col + tx + 1];
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            REF(ty, tx) = reference_d[(start_row + ty + 1) * cols + start_col + tx + 1];
        }
    }

    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;

            SCORE(t_index_y, t_index_x) =
                maximum(SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                        SCORE(t_index_y,     t_index_x - 1) - penalty,
                        SCORE(t_index_y - 1, t_index_x    ) - penalty);
        }
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;

            SCORE(t_index_y, t_index_x) =
                maximum(SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                        SCORE(t_index_y,     t_index_x - 1) - penalty,
                        SCORE(t_index_y - 1, t_index_x    ) - penalty);
        }
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            input_itemsets_d[(start_row + ty + 1) * cols + start_col + tx + 1] =
                SCORE(ty + 1, tx + 1);
        }
    }

#undef SCORE
#undef REF
}

