float dist(Point p1, Point p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float diff = p1.coord[i] - p2.coord[i];
    result += diff * diff;
  }
  return result;
}

static void ensure_pgain_buffers(size_t work_needed, size_t lower_needed) {
  if (work_needed > work_mem_cap) {
    free(work_mem_h);
    work_mem_h = (float*)malloc(work_needed * sizeof(float));
    if (work_mem_h == NULL) {
      fprintf(stderr, "not enough memory for pgain work buffer\n");
      exit(1);
    }
    work_mem_cap = work_needed;
  }
  if (lower_needed > gl_lower_cap) {
    free(gl_lower);
    gl_lower = (float*)malloc(lower_needed * sizeof(float));
    if (gl_lower == NULL) {
      fprintf(stderr, "not enough memory for pgain lower buffer\n");
      exit(1);
    }
    gl_lower_cap = lower_needed;
  }
}

