float pgain(long x, Points *points, float z, long int *numcenters, int kmax,
            bool *is_center, int *center_table, char *switch_membership,
            double *serial_t, double *cpu_gpu_memcpy_t, double *memcpy_back_t,
            double *gpu_malloc_t, double *kernel_t) {
  float gl_cost = 0.0f;

#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;
  kmax++;

  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center[i]) center_table[i] = count++;
  }

#ifdef PROFILE_TMP
  double t2 = gettime();
  *serial_t += t2 - t1;
#endif

  ensure_pgain_buffers((size_t)num * (size_t)kmax, (size_t)kmax);

#ifdef PROFILE_TMP
  double t9 = gettime();
#endif

  memset(switch_membership, 0, num * sizeof(char));
  memset(work_mem_h, 0, (size_t)(K + 1) * (size_t)num * sizeof(float));

  Point xpoint = points->p[x];

#pragma omp parallel for schedule(static)
  for (int thread_id = 0; thread_id < num; thread_id++) {
    float x_cost = 0.0f;
    for (int i = 0; i < dim; i++) {
      float diff = points->p[thread_id].coord[i] - xpoint.coord[i];
      x_cost += diff * diff;
    }
    x_cost *= points->p[thread_id].weight;

    float current_cost = points->p[thread_id].cost;
    int base = thread_id * (K + 1);

    if (x_cost < current_cost) {
      switch_membership[thread_id] = '1';
      work_mem_h[base + K] = x_cost - current_cost;
    } else {
      int assign = (int)points->p[thread_id].assign;
      int addr = base + center_table[assign];
      work_mem_h[addr] += current_cost - x_cost;
    }
  }

#ifdef PROFILE_TMP
  double t10 = gettime();
  *kernel_t += t10 - t9;
#endif

  int numclose = 0;
  gl_cost = z;

#pragma omp parallel for reduction(+:gl_cost,numclose) schedule(static)
  for (int i = 0; i < num; i++) {
    if (is_center[i]) {
      float low = z;
      int ct = center_table[i];
      for (int j = 0; j < num; j++) {
        low += work_mem_h[j * (K + 1) + ct];
      }
      gl_lower[ct] = low;
      if (low > 0) {
        numclose++;
        work_mem_h[i * (K + 1) + K] -= low;
      }
    }
    gl_cost += work_mem_h[i * (K + 1) + K];
  }

  if (gl_cost < 0) {
#pragma omp parallel for schedule(static)
    for (int i = 0; i < num; i++) {
      bool close_center = gl_lower[center_table[points->p[i].assign]] > 0;
      if ((switch_membership[i] == '1') || close_center) {
        points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center[i] && gl_lower[center_table[i]] > 0) is_center[i] = false;
    }

    is_center[x] = true;
    *numcenters = *numcenters + 1 - numclose;
  } else {
    gl_cost = 0;
  }

#ifdef PROFILE_TMP
  double t12 = gettime();
  *serial_t += t12 - t10;
#endif

  (void)cpu_gpu_memcpy_t;
  (void)memcpy_back_t;
  (void)gpu_malloc_t;
  return -gl_cost;
}

float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t* barrier) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  cnt_speedy++;
  (void)pid;
  (void)barrier;

#ifdef PRINTINFO
  fprintf(stderr, "Speedy: facility cost %lf\n", z);
#endif

#pragma omp parallel for schedule(static)
  for (long k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;

  for (long i = 1; i < points->num; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
#pragma omp parallel for schedule(static)
      for (long k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        if (distance * points->p[k].weight < points->p[k].cost) {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign = i;
        }
      }
    }
  }

  float totalcost = z * (*kcenter);
  float mytotal = 0.0f;

#pragma omp parallel for reduction(+:mytotal) schedule(static)
  for (long k = 0; k < points->num; k++) {
    mytotal += points->p[k].cost;
  }

  totalcost += mytotal;

#ifdef PRINTINFO
  fprintf(stderr, "Speedy opened %ld facilities for total cost %lf\n", *kcenter, totalcost);
  fprintf(stderr, "Distance Cost %lf\n", totalcost - z * (*kcenter));
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return totalcost;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter, float e,
          int pid, pthread_barrier_t* barrier) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  (void)pid;
  (void)barrier;
  long i;
  long x;
  float change;
  long numberOfPoints;

  change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0;
    numberOfPoints = points->num;
    (void)numberOfPoints;

    intshuffle(feasible, numfeasible);

    for (i = 0; i < iter; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table,
                      switch_membership, &serial, &cpu_gpu_memcpy, &memcpy_back,
                      &gpu_malloc, &kernel);
    }
    cost -= change;
#ifdef PRINTINFO
    fprintf(stderr, "%ld centers, cost %lf, total distance %lf\n",
            *k, cost, cost - z * (*k));
#endif
  }

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_FL += t2 - t1;
#endif
  return cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, pthread_barrier_t* barrier) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  (void)pid;
  (void)barrier;

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc(numfeasible * sizeof(int));

  float* accumweight;
  float totalweight;
  long k1 = 0;
  long k2 = numfeasible;
  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = (int)k1; i < k2; i++)
      (*feasible)[i] = i;
#ifdef PROFILE_TMP
    double t2 = gettime();
    time_select_feasible += t2 - t1;
#endif
    return numfeasible;
  }

  accumweight = (float*)malloc(sizeof(float) * points->num);
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = (int)k1; i < k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = (int)points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }
  free(accumweight);

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal,
               int pid, pthread_barrier_t* barrier) {
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;
  long k = 0;
  int *feasible = NULL;
  int numfeasible = 0;

  (void)pid;
  (void)barrier;

  hiz = loz = 0.0f;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

#ifdef PRINTINFO
  printf("Starting Kmedian procedure\n");
  printf("%li points in %li dimensions\n", numberOfPoints, ptDimension);
#endif

  float myhiz = 0.0f;
#pragma omp parallel for reduction(+:myhiz) schedule(static)
  for (long kk = 0; kk < points->num; kk++) {
    myhiz += dist(points->p[kk], points->p[0], (int)ptDimension) * points->p[kk].weight;
  }
  hiz = myhiz;

  loz = 0.0f;
  z = (hiz + loz) / 2.0f;

  if (points->num <= kmax) {
#pragma omp parallel for schedule(static)
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    *kfinal = points->num;
    return cost;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k, pid, barrier);
#ifdef PRINTINFO
  printf("thread %d: Finished first call to speedy, cost=%lf, k=%ld\n", pid, cost, k);
#endif
  i = 0;

  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  printf("thread %d: second call to speedy, cost=%lf, k=%ld\n", pid, cost, k);
#endif

  while (k < kmin) {
#ifdef PRINTINFO
    printf("%lf %lf\n", loz, hiz);
    printf("Speedy indicates we should try lower z\n");
#endif
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, (int)kmin, pid, barrier);
  for (int ii = 0; ii < points->num; ii++) {
    is_center[points->p[ii].assign] = true;
  }

  while (1) {
#ifdef PRINTINFO
    printf("loz = %lf, hiz = %lf\n", loz, hiz);
    printf("Running Local Search...\n");
#endif

    lastcost = cost;
    (void)lastcost;
    cost = pFL(points, feasible, numfeasible,
               z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)),
               0.1f, pid, barrier);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
#ifdef PRINTINFO
      printf("Trying a more accurate local search...\n");
#endif
      cost = pFL(points, feasible, numfeasible,
                 z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)),
                 0.001f, pid, barrier);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
  }

  free(feasible);
  *kfinal = k;
  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] +=
          points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

void* localSearchSub(void* arg_) {
  pkmedian_arg_t* arg = (pkmedian_arg_t*)arg_;
  pkmedian(arg->points, arg->kmin, arg->kmax, arg->kfinal, arg->pid, arg->barrier);
  return NULL;
}

void localSearch(Points* points, long kmin, long kmax, long* kfinal) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  omp_set_num_threads(nproc > 0 ? nproc : 1);
  pkmedian(points, kmin, kmax, kfinal, 0, NULL);
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

void outcenterIDs(Points* centers, long* centerIDs, char* outfile) {
  FILE* fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream* stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char* outfile) {
  float* block = (float*)malloc(chunksize * dim * sizeof(float));
  float* centerBlock = (float*)malloc(centersize * dim * sizeof(float));
  long* centerIDs = (long*)malloc(centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[i * dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize * sizeof(Point));
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, chunksize);
    fprintf(stderr, "read %lu points\n", (unsigned long)numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (char*)malloc(points.num * sizeof(char));
    is_center = (bool*)calloc(points.num, sizeof(bool));
    center_table = (int*)malloc(points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");
    contcenters(&points);
    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n");
#endif

    free(is_center);
    free(switch_membership);
    free(center_table);
    is_center = NULL;
    switch_membership = NULL;
    center_table = NULL;

    if (stream->feof()) {
      break;
    }
  }

  switch_membership = (char*)malloc(centers.num * sizeof(char));
  is_center = (bool*)calloc(centers.num, sizeof(bool));
  center_table = (int*)malloc(centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(points.p);
  free(centers.p);
  free(block);
  free(centerBlock);
  free(centerIDs);
}

