class PStream {
public:
  virtual size_t read(float *dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  explicit SimStream(long n_) : n(n_) {}
  size_t read(float *dest, int dim, int num) override {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() override { return 0; }
  int feof() override { return n <= 0; }
  ~SimStream() override {}
private:
  long n;
};

class FileStream : public PStream {
public:
  explicit FileStream(char *filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float *dest, int dim, int num) override {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() override { return std::ferror(fp); }
  int feof() override { return std::feof(fp); }
  ~FileStream() override {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE *fp;
};

