static void ensure_pgain_buffers(long num, int kmax) {
  size_t need_work = (size_t)(kmax + 1) * (size_t)num;
  if (need_work > work_mem_cap) {
    free(work_mem_h);
    work_mem_h = (float *)malloc(need_work * sizeof(float));
    if (!work_mem_h) {
      quit((char *)"not enough memory for work_mem_h");
    }
    work_mem_cap = need_work;
  }
  size_t need_lower = (size_t)(kmax + 1);
  if (need_lower > gl_lower_cap) {
    free(gl_lower);
    gl_lower = (float *)malloc(need_lower * sizeof(float));
    if (!gl_lower) {
      quit((char *)"not enough memory for gl_lower");
    }
    gl_lower_cap = need_lower;
  }
}

void freeDevMem() {
  if (work_mem_h) {
    free(work_mem_h);
    work_mem_h = NULL;
  }
  if (gl_lower) {
    free(gl_lower);
    gl_lower = NULL;
  }
  work_mem_cap = 0;
  gl_lower_cap = 0;
}

void allocDevMem(int num, int, int kmax) {
  ensure_pgain_buffers(num, kmax);
}

