}

void shuffle(Points *points) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  long i, j;
  Point temp;
  for (i = 0; i < points->num - 1; i++) {
    j = (lrand48() % (points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

