float dist(Point p1, Point p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float d = p1.coord[i] - p2.coord[i];
    result += d * d;
  }
  return result;
}

float pspeedy(Points *points, float z, long *kcenter) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  cnt_speedy++;

#ifdef PRINTINFO
  fprintf(stderr, "Speedy: facility cost %lf\n", z);
#endif

#pragma omp parallel for schedule(static)
  for (long k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;

  for (long i = 1; i < points->num; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
#pragma omp parallel for schedule(static)
      for (long k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        float newcost = distance * points->p[k].weight;
        if (newcost < points->p[k].cost) {
          points->p[k].cost = newcost;
          points->p[k].assign = i;
        }
      }
    }
  }

  float totalcost = z * (*kcenter);
  for (long k = 0; k < points->num; k++) {
    totalcost += points->p[k].cost;
  }

#ifdef PRINTINFO
  fprintf(stderr, "Speedy opened %ld facilities for total cost %lf\n", *kcenter, totalcost);
  fprintf(stderr, "Distance Cost %lf\n", totalcost - z * (*kcenter));
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return totalcost;
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax,
            bool *is_center_arr, int *center_table_arr, char *switch_membership_arr,
            double *serial_t, double *cpu_gpu_memcpy_t, double *memcpy_back_t,
            double *gpu_malloc_t, double *kernel_t) {
#ifdef PROFILE_TMP
  double t_gain_start = gettime();
#endif
  (void)cpu_gpu_memcpy_t;
  (void)memcpy_back_t;
  (void)gpu_malloc_t;

  float gl_cost = 0.0f;
  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;

#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      center_table_arr[i] = count++;
    }
  }
#ifdef PROFILE_TMP
  double t2 = gettime();
  *serial_t += t2 - t1;
#endif

  ensure_pgain_buffers(num, kmax);

#ifdef PROFILE_TMP
  double t3 = gettime();
#endif
  memset(switch_membership_arr, 0, num * sizeof(char));
  memset(work_mem_h, 0, (size_t)(K + 1) * (size_t)num * sizeof(float));

  Point px = points->p[x];
#pragma omp parallel for schedule(static)
  for (int thread_id = 0; thread_id < num; thread_id++) {
    float x_cost = 0.0f;
    for (int i = 0; i < dim; i++) {
      float diff = points->p[thread_id].coord[i] - px.coord[i];
      x_cost += diff * diff;
    }
    x_cost *= points->p[thread_id].weight;

    float current_cost = points->p[thread_id].cost;
    int base = thread_id * (K + 1);

    if (x_cost < current_cost) {
      switch_membership_arr[thread_id] = '1';
      work_mem_h[base + K] = x_cost - current_cost;
    } else {
      long assign = points->p[thread_id].assign;
      int addr = base + center_table_arr[assign];
      work_mem_h[addr] += current_cost - x_cost;
    }
  }
#ifdef PROFILE_TMP
  double t4 = gettime();
  *kernel_t += t4 - t3;
#endif

#ifdef PROFILE_TMP
  double t5 = gettime();
#endif
  int numclose = 0;
  gl_cost = z;

  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      float low = z;
      int cidx = center_table_arr[i];
      for (int j = 0; j < num; j++) {
        low += work_mem_h[j * (K + 1) + cidx];
      }
      gl_lower[cidx] = low;

      if (low > 0) {
        numclose++;
        work_mem_h[i * (K + 1) + K] -= low;
      }
    }
    gl_cost += work_mem_h[i * (K + 1) + K];
  }

  if (gl_cost < 0) {
    for (int i = 0; i < num; i++) {
      bool close_center = gl_lower[center_table_arr[points->p[i].assign]] > 0;
      if ((switch_membership_arr[i] == '1') || close_center) {
        points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center_arr[i] && gl_lower[center_table_arr[i]] > 0) {
        is_center_arr[i] = false;
      }
    }

    is_center_arr[x] = true;
    *numcenters = *numcenters + 1 - numclose;
  } else {
    gl_cost = 0;
  }
#ifdef PROFILE_TMP
  double t6 = gettime();
  *serial_t += t6 - t5;
  time_gain += t6 - t_gain_start;
#endif

  return -gl_cost;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter, float e) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  long i;
  long x;
  float change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0f;

    intshuffle(feasible, numfeasible);

    for (i = 0; i < iter; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
                      &serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel);
    }

    cost -= change;
#ifdef PRINTINFO
    fprintf(stderr, "%ld centers, cost %lf, total distance %lf\n", *k, cost, cost - z * (*k));
#endif
  }

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_FL += t2 - t1;
#endif
  return cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc(numfeasible * sizeof(int));

  float *accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = (int)k1; i < k2; i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight = (float *)malloc(sizeof(float) * points->num);
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = (int)k1; i < k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = (int)points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }
  free(accumweight);

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long *kfinal) {
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  long k = 0;
  int *feasible = NULL;
  int numfeasible = 0;

  hiz = loz = 0.0f;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

#ifdef PRINTINFO
  printf("Starting Kmedian procedure\n");
  printf("%li points in %li dimensions\n", numberOfPoints, ptDimension);
#endif

  for (long kk = 0; kk < points->num; kk++) {
    hiz += dist(points->p[kk], points->p[0], (int)ptDimension) * points->p[kk].weight;
  }

  loz = 0.0f;
  z = (hiz + loz) / 2.0f;

  if (points->num <= kmax) {
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    *kfinal = points->num;
    return 0.0f;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k);

#ifdef PRINTINFO
  printf("Finished first call to speedy, cost=%lf, k=%ld\n", cost, k);
#endif

  i = 0;
  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k);
    i++;
  }

#ifdef PRINTINFO
  printf("second call to speedy, cost=%lf, k=%ld\n", cost, k);
#endif

  while (k < kmin) {
#ifdef PRINTINFO
    printf("%lf %lf\n", loz, hiz);
    printf("Speedy indicates we should try lower z\n");
#endif
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, (int)kmin);
  for (int j = 0; j < points->num; j++) {
    is_center[points->p[j].assign] = true;
  }

  while (1) {
#ifdef PRINTINFO
    printf("loz = %lf, hiz = %lf\n", loz, hiz);
    printf("Running Local Search...\n");
#endif

    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
               z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.1f);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
#ifdef PRINTINFO
      printf("Trying a more accurate local search...\n");
#endif
      cost = pFL(points, feasible, numfeasible,
                 z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.001f);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }

    if (cost == lastcost) {
      break;
    }
  }

  free(feasible);
  *kfinal = k;
  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0f - relweight;
        points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points *centers, long *centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

void localSearch(Points *points, long kmin, long kmax, long *kfinal) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  pkmedian(points, kmin, kmax, kfinal);
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

void outcenterIDs(Points *centers, long *centerIDs, char *outfile) {
  FILE *fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int *is_a_median = (int *)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream *stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char *outfile) {
  float *block = (float *)malloc(chunksize * dim * sizeof(float));
  float *centerBlock = (float *)malloc(centersize * dim * sizeof(float));
  long *centerIDs = (long *)malloc(centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[i * dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize * sizeof(Point));
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, chunksize);
    fprintf(stderr, "read %lu points\n", numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = (long)numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (char *)malloc(points.num * sizeof(char));
    is_center = (bool *)calloc(points.num, sizeof(bool));
    center_table = (int *)malloc(points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");
    contcenters(&points);
    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n");
#endif
    free(is_center);
    free(switch_membership);
    free(center_table);
    is_center = NULL;
    switch_membership = NULL;
    center_table = NULL;

    if (stream->feof()) {
      break;
    }
  }

  switch_membership = (char *)malloc(centers.num * sizeof(char));
  is_center = (bool *)calloc(centers.num, sizeof(bool));
  center_table = (int *)malloc(centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  is_center = NULL;
  switch_membership = NULL;
  center_table = NULL;

  free(points.p);
  free(centers.p);
  free(block);
  free(centerBlock);
  free(centerIDs);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc < 11) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc [-p platform] [-d device]\n",
            argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "  platform:    Platform id\n");
    fprintf(stderr, "  device:      Device id\n");
    fprintf(stderr, "\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }

  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);
  _clCmdParams(argc, argv);

#ifdef TIMING
  gettimeofday(&tv_total_start, NULL);
#endif

  try {
    _clInit(platform_id, device_id);
  } catch (std::string &msg) {
    std::cout << "exception caught in main function->" << msg << std::endl;
    return -1;
  }

#ifdef TIMING
  gettimeofday(&tv_init_end, NULL);
  tvsub(&tv_init_end, &tv_total_start, &tv);
  init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

  srand48(SEED);
  omp_set_dynamic(0);
  if (nproc > 0) omp_set_num_threads(nproc);

  PStream *stream;
  if (n > 0) {
    stream = new SimStream(n);
  } else {
    stream = new FileStream(infilename);
  }

#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif

#ifdef PROFILE_TMP
  serial = 0.0;
  cpu_gpu_memcpy = 0.0;
  gpu_malloc = 0.0;
  gpu_free = 0.0;
  kernel = 0.0;
  time_FL = 0.0;
  cnt_speedy = 0;
#endif

  std::cout << "before sc" << std::endl;
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);
  std::cout << "after sc" << std::endl;

#ifdef PROFILE_TMP
  gpu_free = gettime();
#endif

#ifdef TIMING
  gettimeofday(&tv_close_start, NULL);
#endif

  freeDevMem();

#ifdef PROFILE_TMP
  gpu_free = gettime() - gpu_free;
#endif

  _clRelease();

#ifdef TIMING
  gettimeofday(&tv_close_end, NULL);
  tvsub(&tv_close_end, &tv_close_start, &tv);
  close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  printf("time = %lf\n", t2 - t1);
#endif

  delete stream;

#ifdef TIMING
  tvsub(&tv_close_end, &tv_total_start, &tv);
  total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

  printf("Init: %f\n", init_time);
  printf("MemAlloc: %f\n", mem_alloc_time);
  printf("HtoD: %f\n", h2d_time);
  printf("Exec: %f\n", kernel_time);
  printf("DtoH: %f\n", d2h_time);
  printf("Close: %f\n", close_time);
  printf("Total: %f\n", total_time);
#endif

#ifdef PROFILE_TMP
  printf("time pgain = %lf\n", time_gain);
  printf("time pgain_dist = %lf\n", time_gain_dist);
  printf("time pgain_init = %lf\n", time_gain_init);
  printf("time pselect = %lf\n", time_select_feasible);
  printf("time pspeedy = %lf\n", time_speedy);
  printf("time pshuffle = %lf\n", time_shuffle);
  printf("time FL = %lf\n", time_FL);
  printf("time localSearch = %lf\n", time_local_search);
  printf("\n");
  printf("====GPU Timing info====\n");
  printf("time serial = %lf\n", serial);
  printf("time CPU to GPU memory copy = %lf\n", cpu_gpu_memcpy);
  printf("time GPU to CPU memory copy back = %lf\n", memcpy_back);
  printf("time GPU malloc = %lf\n", gpu_malloc);
  printf("time GPU free = %lf\n", gpu_free);
  printf("time kernel = %lf\n", kernel);

  FILE *fp = fopen("PD.txt", "w");
  fprintf(fp, "%lf, %lf, %lf, %lf, %lf, %lf, %lf, %lf, %lf\n",
          time_FL, cpu_gpu_memcpy, memcpy_back, kernel, gpu_malloc, gpu_free, 0.0, 0.0, 0.0);
  fclose(fp);
#endif

  _clStatistics();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_end();
#endif

  delete[] outfilename;
  delete[] infilename;
  return 0;
}
